SELECT epo.SEQ, epo.RESUME_SEQ, epo.EVS_TYPE, GET_CODE_NAME(epo.EVS_TYPE,#{lang, jdbcType=VARCHAR}) EVS_TYPE_NAME, epo.CODE_NO, epo.CODE_NAME, epo.FORMULA, (SELECT CODE_NAME FROM EVS_FORMULA WHERE SEQ = epo.FORMULA) FORMULA_NAME, epo.IS_INCLUDE, epo.EVS_GRADE, GET_CODE_NAME(epo.EVS_GRADE,#{lang, jdbcType=VARCHAR}) EVS_GRADE_NAME, epo.ACTIVITY, TO_CHAR(epo.ORDERNO) AS ORDER_NO, TO_CHAR(epo.CREATE_DATE, 'YYYY-MM-DD HH24:MI:SS') AS CREATE_DATE, GET_UPDATED_INFO(epo.CREATED_BY) || ' ' || epo.CREATED_IP AS CREATED_BY, TO_CHAR(epo.UPDATE_DATE, 'YYYY-MM-DD HH24:MI') AS UPDATE_DATE, GET_UPDATED_INFO(epo.UPDATED_BY) || ' ' || epo.UPDATED_IP AS UPDATED_BY FROM EVS_PARAM_OBJECT epo WHERE ACTIVITY != 2
AND epo.RESUME_SEQ = #{resumeSeq, jdbcType=VARCHAR}
ORDER BY epo.SEQ

